  },
  {
    name: "Chevy Tahoe/Suburban",
    boltPattern: "6x139.7",
    centerBore: 78.1,
    priority: 2,
    description: "Full-size SUV platform",
  },
  {
    name: "GMC Sierra 1500",
    boltPattern: "6x139.7",
    centerBore: 78.1,
    priority: 2,
    description: "GMC truck platform",
  },

  // ═══════════════════════════════════════════════════════════════════════════
  // PRIORITY 3: Additional coverage
  // ═══════════════════════════════════════════════════════════════════════════
  {
    name: "Toyota Tundra",
    boltPattern: "5x150",
    centerBore: 110.1,
    priority: 3,
    description: "Full-size Toyota truck",
  },
  {
