    vehicleClass = 'suv';
  }

  // Import and use aftermarket sizing function
  const { generateAftermarketTireSizes } = require("@/lib/tirePlusSizing");
  return generateAftermarketTireSizes(
    Math.round(wheelDiaNum),
    Number.isFinite(wheelWidthNum) ? wheelWidthNum : undefined,
    vehicleClass
  );
})();

